import { isNullOrUndefined } from './utils';

export const isObject = (obj) => {
  return obj !== undefined && obj !== null && obj.constructor == Object;
};

export const isArray = (obj) => {
  return obj !== undefined && obj !== null && obj.constructor == Array;
};

export const isDate = (obj: any): boolean => {
  return obj instanceof Date && !isNaN(obj.getTime());
};

export const getStoreQueries = (formId: string) => {
  const fromData = localStorage.getItem(formId);
  if (!isNullOrUndefined(fromData)) {
    return JSON.parse(fromData);
  } else {
    return {};
  }
};

export const storeQuery = (formId: string, queryId: string, queryData: object) => {
  const queries = getStoreQueries(formId);
  queries[queryId] = queryData;
  localStorage.setItem(formId, JSON.stringify(queries));
};

export const removeQuery = (formId: string, queryId: string) => {
  const queries = getStoreQueries(formId);
  delete queries[queryId];
  if (Object.keys(queries).length > 0) {
    localStorage.setItem(formId, JSON.stringify(queries));
    return;
  }
  localStorage.removeItem(formId);
};

export const queryPanelItemSuffix = {
  DEFAULT_SUFFIX: '(default)',
  MODIFIED_SUFFIX: '(modified)',
  MODIFIED: '(modified',
  modifiedSuffixWithNumber: (n: number) => `(modified ${n})`
};


export const debounce = <F extends (...args: any[]) => any>(func: F, waitFor: number) => {
  let timeout: ReturnType<typeof setTimeout> | null = null;
  const debounced = (...args: Parameters<F>) => {
    if (timeout !== null) {
      clearTimeout(timeout);
      timeout = null;
    }
    timeout = setTimeout(() => func(...args), waitFor);
  };
  return debounced as (...args: Parameters<F>) => ReturnType<F>;
};

