import { Component, Element, Event, EventEmitter, h, Host, Listen, Method, Prop, State, Watch } from '@stencil/core';
import { isNullOrUndefined, closeAllDropdownsInZG } from '@src/utils/mx-utils/utils';
import { EventTypes, KeyboardCodes } from '@src/utils/mx-utils/Events';
import { getOffset } from '@src/utils/mx-utils/domUtils';
import { debounce } from '@src/utils/mx-utils';
import itemUtils from '@src/utils/mx-utils/mx-menu-item.utils';
import {
  CustomKeysV2,
  IMenuItemV2,
  MenuItemV2StateMap
} from '@src/mx-components/menu-item/mx-menu-item-v2/mx-menu-item-v2.model';
import { calculateVirtualizationData, IVirtualizationData } from '@src/utils/mx-utils/virtualization.utils';

interface IFlattenedMenuItemV2 extends IMenuItemV2 { superParentId: string }

/**
 * A multi-select dropdown presents a list of options from which a user can select more than one option at a time.
 * These selected options can represent values in a form, or can be used as an action to filter or sort existing content.
 */
@Component({
  tag: 'mx-multi-select-v2',
  styleUrl: 'mx-multi-select-v2.css'
})
export class MxMultiSelectV2 {

  @Element() hostEl: HTMLMxMultiSelectV2Element;

  /*--------------------------------------------------------------------------------------------------------properties*/
  /** Array of objects that represent items for the user to select.
   *  Objects must have a label, value and selected for example: {label: 'Carrot', value: 'carrot'}. */
  @Prop() readonly items: IMenuItemV2[] | string[] = [];
  /** Array of items that are currently selected. */
  @Prop() readonly selectedItems: IMenuItemV2[] | string[] = []; // this field for angular value accessor
  /** If true and there is only one item selected show selected item label instead of '1 item selected'. */
  @Prop() readonly showSelectedLabel: boolean = false;
  /** The visible label text for the dropdown. */
  @Prop() readonly label: string;
  /** The id used for the label attr. for and input attr.id. */
  @Prop() readonly inputId: string;
  /** Disables the dropdown menu, set to false by default. */
  @Prop() readonly isDisabled: boolean;
  /** Allows for setting the optional text displayed. */
  @Prop() readonly optionalText: string;
  /** When true, the size of the dropdown input is smaller. Set to false by default. */
  @Prop() readonly isCompact: boolean;
  /** Sets the aria-label. */
  @Prop() readonly ariaLabel: string;
  /** Displays the optionalText next to the label. */
  @Prop() readonly displayOptionalText: boolean = false;
  /** Sets whether a filter search is visible. */
  @Prop() readonly displayFilterSearch: boolean = false;
  /** Sets the number of keystrokes on which filter search should trigger the search. */
  @Prop() readonly keyStrokes: number = 0;
  /** Sets placeholder content in the filter search to provide additional information. */
  @Prop() readonly filterSearchPlaceholder: string = '';
  /** Provide placeholder text to select list. */
  @Prop() readonly placeHolder: string = 'Select One';
  /** Sets the style rules. */
  @Prop() readonly styleRules: string;
  /** Sets error class in dropdown. */
  @Prop() readonly hasError: boolean = false;
  /** Sets the width of the container. */
  @Prop() readonly width: string = '100%';
  /** Sets the padding-left property. */
  @Prop() readonly paddingLeft: string = '0';
  /** Returns values ONLY array of select items if true.
   *  This option is not applicable if the multi-select is having nested values (parent-child relationship). */
  @Prop() readonly emitOnlyValue: boolean = false;
  /** Renders a drop-up menu instead of dropdown if the select is less than 220px above viewport bottom. */
  @Prop() readonly enableDropUp: boolean = true;
  /** Overrides the dropdown's bottom position to one of your choosing in px. */
  @Prop() readonly dropdownBottomPosition: number;
  /** Sets checkboxes to Compact KDS checkbox. */
  @Prop() readonly compactCheckbox: boolean;
  /** Enables selected tag list. */
  @Prop() readonly enableTagList: boolean = false;
  /** Target dropdown options list to attach the dialog,
   *  valid values are "body" or a local ng-template variable of another element. */
  @Prop() readonly appendTo: any;
  /** Sets the width of the list container(left side). */
  @Prop() readonly listWidth: string = '100%';
  /** Sets whether to display an option to clear your selection. */
  @Prop() readonly enableClearSelection: boolean = false;
  /** Hides the dropdown section of multi-select. */
  @Prop() readonly hideDropdown: boolean = false;
  /** Sets the element name. Used for integration within query panel. */
  @Prop({ reflect: true, attribute: 'name' }) readonly name: string;
  /** Sets custom keys. */
  @Prop() readonly customKeys: CustomKeysV2 = { key: '', value: '' };
  /** Enables virtual scrolling. */
  @Prop() readonly enableVirtualScroll: boolean = false;

  /*------------------------------------------------------------------------------------------------------------states*/
  @State() isOpen = false;
  @State() searchText = '';
  @State() selectedLabel: string;
  @State() initInputWithFocus = false;
  @State() tagItemWidth: number | null = null;
  @State() flattenedSelectedItems: IFlattenedMenuItemV2[] = [];
  @State() selectedItemsMap: MenuItemV2StateMap = {};
  /** Stores tags container scrolling position */
  @State() private tagsContainerScrollTop = 0;

  /*-----------------------------------------------------------------------------------------------------------watches*/
  //watching this isOpen to set the shouldFireOpenRendered = true so that we can re-calculate
  //the height after listening to dropdownOpenRendered so that dropdown list is visible without scrolling in section-accordion
  @Watch('isOpen')
  checkIsOpen(newOpen: boolean, prevOpen: boolean): void {
    if (newOpen === true && prevOpen === false) {
      this.shouldFireOpenRendered = true;
    }
  }

  @Watch('items')
  handleItemsChange(newItems: IMenuItemV2[] | string[]): void {
    this.updateFlattenedSelectedItems(newItems);
  }

  @Watch('selectedItems')
  onSelectedItemsChange(newSelectedItems: IMenuItemV2[] | string[]): void {
    this.selectedItemsMap = itemUtils.composeItemsStateMap(newSelectedItems, this.customKeys);
  }

  /*------------------------------------------------------------------------------------------------------------events*/
  /** If true 'Select All' will disappear on search */
  /** Emits event on dropdown change with selectedItems list. */
  @Event() selectionChanged: EventEmitter<{ items: IMenuItemV2[], plainSelectedItems: IMenuItemV2[] | string[] }>;
  /** Emits event whenever input is blurred. */
  @Event() inputBlur: EventEmitter;
  /** Emits event whenever the dropdown is closed. */
  @Event() dropdownClose: EventEmitter<HTMLDivElement>;
  /** Emits event whenever dropdown is opened. */
  @Event() dropdownOpen: EventEmitter<HTMLDivElement>;
  /** Event fired when dropdown is opened after it has been rendered. */
  @Event() dropdownOpenRendered: EventEmitter<HTMLDivElement>;

  /*-----------------------------------------------------------------------------------------------------------methods*/
  /** Toggles the opened status of the dropdown. Optionally, you may pass in a value to show it or hide it. */
  @Method()
  async toggleDropdown(toggle?: boolean): Promise<void> {
    if (!isNullOrUndefined(toggle)) {
      this.isOpen = toggle;
    } else {
      this.isOpen = !this.isOpen;
    }
  }

  /*---------------------------------------------------------------------------------------------------------listeners*/
  @Listen('click', { target: 'document' })
  docClick(event: MouseEvent): void {
    const target: HTMLElement = event.target as HTMLElement;
    if (this.isOpen) {
      const outsideClick: boolean = this.isNotListContainer(target);
      if (outsideClick && this.tagRemoval && target.className === 'clear-link') {
        this.tagRemoval = false;
      }
      if (outsideClick || this.isDropdownLabel(target)) {
        this.closeDropdown();
      }
    }
  }

  @Listen('keydown', { target: 'document' })
  spacebarKey(event: KeyboardEvent): boolean {
    if (event.code === 'Escape') {
      this.closeDropdown();
    }
    return !(event.code === 'Space' &&
      (event.target as HTMLElement).classList.value.includes('mx-dropdown-input-wrapper'));
  }

  @Listen('focus', { target: 'document' })
  focusHandler(): void {
    const inputComponent = this.hostEl.querySelector('.mx-dropdown-input-wrapper');
    (inputComponent as HTMLElement).focus();
  }

  @Listen('resize', { target: 'window' })
  handleResize(): void {
    this.tagItemWidth = this.getTagItemWidth();
  }

  /*----------------------------------------------------------------------------------------------------private-fields*/
  private searchInputElement: HTMLMxSearchInputElement;
  //this variable is set to track  isOpen state and fired the dropdownOpenRendered to recalculate the dropdown height
  private tagsWrapperElement: HTMLDivElement;
  private shouldFireOpenRendered: boolean;
  private tagListHeight: number;
  private tagRemoval = false;
  private spaceBelow = 500;
  private listContainer: HTMLDivElement;
  private menuItemListV2: HTMLMxMenuItemV2ListElement = null;
  private readonly tagSummaryHeight = 20;

  /*---------------------------------------------------------------------------------------component-lifecycle-methods*/
  componentWillLoad(): void {
    if (this.items && this.items.length > 0) {
      this.selectedItemsMap = itemUtils.composeItemsStateMap(this.selectedItems, this.customKeys);
      this.updateFlattenedSelectedItems(this.items);
    }
  }

  componentDidUpdate(): void {
    this.shouldFireOpenRendered && this.dropdownOpenRendered.emit();
    this.shouldFireOpenRendered = false;
    if (this.initInputWithFocus && !isNullOrUndefined(this.searchInputElement)) {
      this.searchInputElement.setFocus().then(console.debug);
      this.initInputWithFocus = false;
    }
  }

  /*------------------------------------------------------------------------------------------------------------render*/
  private readonly renderTag = (item: IFlattenedMenuItemV2, width: string, index: number) => {
    const label: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.key] : item.label;
    return <span
      class={{
        'selected-tag-wrapper': true,
        'selected-tag-wrapper_disabled': item.disabled
      }}
      style={{ width }}>
      <kds-tag
        key={index}
        compact={this.isCompact}
        style={{ width: '100%' }}
        class='selected-tag flex justify-between'
        kind='action'
        dismissable={true}
        removeSelf={false}
        onClick={(e) => e.preventDefault()}
        onTagRemoved={this.onTagRemoval(item, item.superParentId)}>
        <span title={label}>{label}</span>
      </kds-tag>
    </span>;
  }

  render() {
    // this is the height of the summary block with the label and 'clear all link'
    // we need to subtract this height from the visible window height to calculate start index
    // and other virtualization data
    const tagListContainerHeight: number = this.tagListHeight - this.tagSummaryHeight;
    let paddingTop = 0;
    let paddingBottom = 0;
    let overallHeight = 'auto';
    let tags: IFlattenedMenuItemV2[] = this.flattenedSelectedItems || [];
    if (this.enableVirtualScroll) {
      const virtualizationData: IVirtualizationData = calculateVirtualizationData(
        this.flattenedSelectedItems,
        tagListContainerHeight,
        this.tagsContainerScrollTop,
        () => 28,
        2);
      const startIndex = virtualizationData.startIndex;
      const lastIndex = startIndex + virtualizationData.length;
      paddingTop = virtualizationData.paddingTop;
      paddingBottom = virtualizationData.paddingBottom;
      overallHeight = virtualizationData.overallHeight + 'px';
      tags = tags.slice(startIndex, lastIndex);
    }

    return (<Host>
      <div
        class='mx-dropdown-wrapper'
        style={{ width: this.width }}>
        {this.label && this.label?.length > 0 && (<kds-label
          labelClass={'mx-label dropdown-label' + (this.hasError ? ' text-negative-less-prominent' : '')}
          inner-htmlFor={this.inputId}>
          {this.label}
          {this.displayOptionalText && (
            <span class={{
              'optional-text': true,
              'text-secondary': !this.hasError,
              'text-negative-less-prominent': this.hasError
            }}>
              {this.optionalText?.length > 1 ? <span>({this.optionalText})</span> : '(Optional)'}
            </span>
          )}
        </kds-label>)}

        <div
          class={{
            'mx-dropdown-input-wrapper': true,
            'border-negative-less-prominent': this.hasError,
            'text-secondary': this.isDisabled,
            disabled: this.isDisabled,
            'bg-quaternary-fill': this.isDisabled,
            compact: this.isCompact,
            open: this.isOpen
          }}
          onClick={this.toggleOptionsMenu}
          onKeyUp={this.toggleOptionsMenu}
          title={this.selectedLabel?.length > 0 ? this.selectedLabel : this.placeHolder}
          aria-label={this.label?.length > 0 ? this.label : this.ariaLabel}
          tabindex={this.isDisabled ? -1 : 0}>
          <span
            class={{
              'mx-dropdown-label': true,
              disabled: this.isDisabled,
              open: this.isOpen
            }}
            style={{ paddingLeft: this.paddingLeft }}>
            {this.selectedLabel?.length > 0 ? this.selectedLabel : this.placeHolder}
          </span>
          {this.enableClearSelection && (
            <kds-icon-close
              size='s'
              class='mx-dropdown-icon'
              tabindex='0'
              onClick={this.clearSelection}></kds-icon-close>
          )}
          <kds-icon-chevron-down
            class={{
              'mx-dropdown-icon': true,
              disabled: this.isDisabled,
              open: this.isOpen
            }}
            size='m'></kds-icon-chevron-down>
        </div>

        <div
          style={{ display: this.isOpen && !isNullOrUndefined(this.items) ? 'block' : 'none' }}
          ref={(el) => this.listContainer = el}>
          <div
            class={{
              'multi-select-mx-dropdown-list': true,
              'drop-up': this.enableDropUp && this.spaceBelow <= 220,
              'is-compact': this.isCompact,
              'open-tag-list': this.isOpenTagList(),
              'has-search': this.displayFilterSearch
            }}
            style={{
              width: this.listWidth,
              bottom: `${this.dropdownBottomPosition - 1}px`
            }}>

            {this.displayFilterSearch &&
              <mx-search-input
                ref={(ref) => this.searchInputElement = ref}
                class='filter-search'
                keyStrokes={this.keyStrokes}
                placeholder={this.filterSearchPlaceholder}
                onFocusout={this.inputBlur.emit}
                onInputChanged={debounce(this.handleFilterChange, 700)}
                value={this.searchText}
                is-compact={this.isCompact} />
            }

            <div style={{ width: 'round(up, 100%, 1px)', marginTop: '-1px' }}>
              <mx-menu-item-v2-list
                ref = {(el) => this.menuItemListV2 = el}
                class='mx-multi-select-list'
                fix-input={true}
                query={this.searchText}
                items={this.items}
                customKeys={this.customKeys}
                showCheckbox={true}
                showCheckboxForStringItems={true}
                selectedItems={this.selectedItems}
                serviceItemsCompact={this.compactCheckbox}
                compactCheckbox={this.compactCheckbox}
                enableVirtualScroll={this.enableVirtualScroll}
                onHeightChanged={this.heightChangeHandler.bind(this)}
                onItemsSelected={this.itemsSelectedHandler.bind(this)}
              />
            </div>
          </div>

          { this.enableTagList &&
            this.isOpen &&
            this.flattenedSelectedItems !== undefined &&
            this.flattenedSelectedItems.length > 0 &&
            (<div
              class={{
                'mx-dropdown-tags-wrapper': true,
                'is-compact': this.isCompact,
                'no-search': !this.displayFilterSearch,
                'drop-up': this.enableDropUp && this.spaceBelow <= 220
              }}
              ref={(el) => this.tagsWrapperElement = el}
              style={{
                width: `round(up, ${this.width}, 1px)`,
                left: this.listWidth != null ? this.listWidth : this.width,
                height: this.tagListHeight + 'px',
                // this bottom is a bottom of the input, so we need to subtract the height of the tag list to position it correctly
                // also 1px is added as item list has margin top -1px
                bottom: `${(this.dropdownBottomPosition || 0) - this.tagListHeight + 1 }px`
              }}>
              <div class='tag-summary'>
                <span class='truncate' title={this.selectedLabel}>{this.selectedLabel}</span>
                <kds-link
                  onClick={this.clearSelection.bind(this)}
                  size='m'
                  class='float-right clear-link'
                  tabindex='0'>Clear All
                </kds-link>
              </div>
              <div
                class='overflow-y-auto'
                style={{ overflowAnchor: 'none', height: tagListContainerHeight + 'px' }}
                onScroll={(event: UIEvent) => {
                  if (this.enableVirtualScroll) {
                    this.tagsContainerScrollTop = (event.target as HTMLDivElement).scrollTop;
                  }
                }}>
                <div
                  class='mx-dropdown-tags-container'
                  style={{
                    paddingTop: paddingTop + 'px',
                    paddingBottom: paddingBottom + 'px',
                    height: overallHeight
                  }}>
                  { tags.map((item: IFlattenedMenuItemV2, index: number) => this.renderTag(item, '50%', index)) }
                </div>
              </div>
            </div>)}
        </div>
      </div>
    </Host>);
  }
  /*-------------------------------------------------------------------------------------------------------ui-handlers*/
  private heightChangeHandler(event: CustomEvent<{ height: number }>): void {
    this.tagListHeight = event.detail.height + 2; // adding 2px for border
  }

  private itemsSelectedHandler(event: CustomEvent<{ selectedItems: IMenuItemV2[] }>): void {
    const selectedItems: IMenuItemV2[] = event.detail.selectedItems;
    this.processSelectedItems(selectedItems);
  }

  private readonly clearSelection = (event: MouseEvent): Promise<void> => {
    event.preventDefault();
    event.stopPropagation();
    if (this.isDisabled) {
      return;
    }
    this.flattenedSelectedItems = [];
    this.updateSelectedLabel();
    this.menuItemListV2.unselectAllItems().then((event) => {
      this.itemsSelectedHandler({ detail: { selectedItems: event.selectedItems } } as CustomEvent);
    });
  };

  private readonly handleFilterChange = (event: CustomEvent): void => {
    if (event && !isNullOrUndefined(event.detail)) {
      this.searchText = event.detail.searchText;
    }
  };

  /*---------------------------------------------------------------------------------------------------private-methods*/
  private readonly isDropdownLabel = (target): boolean => {
    return target && this.hostEl.contains(target) && target.classList.contains('dropdown-label');
  };

  private readonly isNotListContainer = (target): boolean => {
    return target && !this.hostEl.contains(target) && !this.listContainer.contains(target);
  };

  private getSpaceBelowFromViewport(): void {
    const elementOffset = getOffset(this.hostEl);
    this.spaceBelow = window.innerHeight - elementOffset.bottom;
  }

  private updateSelectedLabel(): void {
    this.selectedLabel = this.getDropdownLabel(this.flattenedSelectedItems);
  }

  private readonly onTagRemoval = (item: IMenuItemV2, superParentId: string) => (_event: CustomEvent): void => {
    this.tagRemoval = true;
    this.menuItemListV2.unselectSingleItem(item, superParentId).then((result: { selectedItems: IMenuItemV2[] }) => {
      this.processSelectedItems(result.selectedItems);
    });
  };

  private getDropdownLabel(items: IMenuItemV2[] | string[]): string {
    const SELECT_ONE: string = this.placeHolder;
    const counter: number = items.length || 0;
    if (counter > 1) {
      return `${counter} Items Selected`;
    } else if (counter === 1) {
      if (this.showSelectedLabel) {
        return this.getSelectedChildLabel(this.flattenedSelectedItems);
      }
      return '1 Item Selected';
    } else {
      return SELECT_ONE;
    }
  }

  private getSelectedChildLabel(items: IMenuItemV2[]): string {
    return items[0].hasOwnProperty('children') && items[0].children.length > 0 ?
      this.getSelectedChildLabel(items[0].children) :
      items[0].label;
  }

  private readonly toggleOptionsMenu = (event): void => {
    if (!this.isDisabled) {
      const eventCodeOrType = event.code !== undefined ? event.code : event.type;
      switch (eventCodeOrType) {
        case KeyboardCodes.SPACE:
        case KeyboardCodes.ENTER:
        case KeyboardCodes.NUMPAD_ENTER:
        case EventTypes.CLICK:
          this.actionToPerformOnToggle();
          break;
        case KeyboardCodes.ESCAPE:
          this.closeDropdown();
          break;
      }
    }
  };

  private async actionToPerformOnToggle(): Promise<void> {
    this.getSpaceBelowFromViewport();
    if (this.isOpen) {
      this.closeDropdown();
      return;
    }
    // If this is used inside ZingGrid, we need to close all other dropdowns before opening this one.
    await closeAllDropdownsInZG(this.hostEl);
    this.isOpen = !this.isOpen;
    if (this.isOpen) {
      if (this.appendTo) {
        this.setListOverlay();
      }
      this.dropdownOpen.emit(this.listContainer);
      this.handleFilterChange(null);
      this.initInputWithFocus = true;
    }
  }

  private setListOverlay(): void {
    if (!isNullOrUndefined(this.appendTo)) {
      if (this.appendTo === 'body') {
        document.body.appendChild(this.listContainer);
      } else {
        this.appendTo.appendChild(this.listContainer);
      }
    }
  }

  private closeDropdown(): void {
    this.isOpen = false;
    this.searchText = '';
    this.dropdownClose.emit(this.listContainer);
  }

  private readonly isOpenTagList = (): boolean => {
    return this.isOpen &&
      this.enableTagList &&
      this.flattenedSelectedItems !== undefined &&
      this.flattenedSelectedItems?.length > 0;
  }

  private readonly getTagItemWidth = (): number => {
    // We need to calculate the width of what the tag should be based on the available width in the container.
    // The container has 10 pixels of horizontal padding and a 1 pixel border on the right that need to be removed to account for available space.
    // The tags themselves have a 1 pixel border on the left and right, so we need to remove 2 pixels from the width of each tag.
    const TAG_CONTAINER_SPACING = 13;
    const TAGS_PER_ROW = 2;
    if(this.tagsWrapperElement) {
      return (this.tagsWrapperElement.clientWidth - TAG_CONTAINER_SPACING) / TAGS_PER_ROW ;
    } else {
      const componentWrapper = this.hostEl.querySelector('.mx-dropdown-wrapper');
      return (componentWrapper.clientWidth - TAG_CONTAINER_SPACING) / TAGS_PER_ROW;
    }
  };

  private updateFlattenedSelectedItems(items: IMenuItemV2[] | string[], ignoreSelectedMap = false): void {
    const plainSelectedItems: IFlattenedMenuItemV2[] = [];
    this.fillFlattenedItems(items, ignoreSelectedMap, plainSelectedItems, null, 0);
    this.flattenedSelectedItems = plainSelectedItems;
    this.updateSelectedLabel();
  }

  private fillFlattenedItems(
    items: IMenuItemV2[] | string[],
    ignoreSelectedMap: boolean,
    plainSelectedItems: IFlattenedMenuItemV2[],
    superParentId: string,
    level: number): void {

    if (items && items.length > 0) {
      items.forEach((item: IMenuItemV2 | string) => {
        const itemObject: IMenuItemV2 = itemUtils.convertStringToItem(item, this.compactCheckbox, true);
        const value: string = itemUtils.hasCustomKeys(this.customKeys) ?
          itemObject[this.customKeys.value] :
          itemObject.value;
        superParentId = level === 0 ? value : superParentId;
        const isInSelectedItems: boolean = ignoreSelectedMap ?
          false :
          this.selectedItemsMap.hasOwnProperty(value);
        if (isInSelectedItems ||
          (itemObject.selected && (itemObject.children == null || itemObject.children.length === 0))) {
          plainSelectedItems.push({ ...itemObject, superParentId });
        }
        this.fillFlattenedItems(itemObject.children, ignoreSelectedMap, plainSelectedItems, superParentId, level + 1);
      });
    }
  }

  private processSelectedItems(selectedItems: IMenuItemV2[]): void {
    this.updateFlattenedSelectedItems(selectedItems, true);
    this.selectionChanged.emit({
      items: selectedItems,
      plainSelectedItems: this.emitOnlyValue ?
        this.flattenedSelectedItems
          .map((item: IMenuItemV2) =>
            itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value) :
        this.flattenedSelectedItems
    });
  }
}
